class Solution {
    public long minimumSteps(String s) {
        long steps = 0;
        long ones = 0;
        for (char c : s.toCharArray()) {
            if (c == '1') {
                ones++;
            } else {
                steps += ones;
            }
        }
        return steps;
    }
}
```
